import { useState, useEffect } from 'react';

export function useDramaticCounter(): () => void {
  const [count, setCount] = useState<number>(0);

  useEffect(() => {
    if (count > 5) {
      console.warn('TypeScript avait prévenu.');
    }
  }, [count]);

  return () => setCount(c => c + 1);
}

